/* userSettingsMapper.selectAccountTotalCount */
SELECT
	COUNT(1)
FROM
	TB_ACCOUNT_INFO
WHERE
	MEMBER_ID = #{userId}
AND
	DEL_YN = 'N'

	AND AI_SE = #{aiSe}


	AND CARD_TYPE = #{cardType}


	AND USE_YN = #{useYn}


	AND AI_NM LIKE CONCAT('%', #{aiNm} ,'%')

/* userSettingsMapper.selectAccountList */ SELECT AI_SEQ AS aiSeq ,AI_SE AS aiSe ,CASE WHEN AI_SE = 'B' THEN (SELECT BANK_NAME FROM BANK_CODE WHERE BANK_CODE = AI_CODE) ELSE (SELECT CARD_NAME FROM CARD_CODE WHERE CARD_CODE = AI_CODE) END AS aiCode ,AI_NM AS aiNm ,CARD_TYPE AS cardType ,SPEND_BGN_MT_SE AS spendBgnMtSe ,SPEND_BGN_DAY AS spendBgnDay ,SPEND_END_MT_SE AS spendEndMtSe ,SPEND_END_DAY AS spendEndDay ,USE_YN AS useYn ,DATE_FORMAT(REG_DT, '%Y-%m-%d') AS regDt FROM TB_ACCOUNT_INFO WHERE MEMBER_ID = #{userId} AND DEL_YN = 'N'
AND AI_SE = #{aiSe}
AND CARD_TYPE = #{cardType}
AND USE_YN = #{useYn}
AND AI_NM LIKE CONCAT('%', #{aiNm} ,'%')
ORDER BY REG_DT DESC LIMIT #{offset}, #{pageSize}

mapper.insert:
/* userSettingsMapper.insertAccount */
INSERT INTO TB_ACCOUNT_INFO (
	 MEMBER_ID
	,AI_SEQ
	,AI_SE
	,AI_CODE
	,AI_NM
	,CARD_TYPE
	,SPEND_BGN_MT_SE
	,SPEND_BGN_DAY
	,SPEND_END_MT_SE
	,SPEND_END_DAY
	,AI_RM
	,USE_YN
	,DEL_YN
	,REG_ID
	,REG_DT
	,UPD_ID
	,UPD_DT
) VALUES (
	 #{userId}
	,#{aiSeq}
	,#{aiSe}
	,#{aiCode}
	,#{aiNm}
	,#{cardType}
	,#{spendBgnMtSe}
	,#{spendBgnDay}
	,#{spendEndMtSe}
	,#{spendEndDay}
	,#{aiRm}
	,#{useYn}
	,'N'
	,#{userId}
	,now()
	,#{userId}
	,now()
)

mapper.update:
/* userSettingsMapper.updateAccount */
UPDATE TB_ACCOUNT_INFO
SET
	 AI_SE 				= #{aiSe}
	,AI_CODE 			= #{aiCode}
	,AI_NM 				= #{aiNm}
	,CARD_TYPE 			= #{cardType}
	,SPEND_BGN_MT_SE 	= #{spendBgnMtSe}
	,SPEND_BGN_DAY 		= #{spendBgnDay}
	,SPEND_END_MT_SE 	= #{spendEndMtSe}
	,SPEND_END_DAY 		= #{spendEndDay}
	,AI_RM 				= #{aiRm}
	,USE_YN 			= #{useYn}
	,UPD_ID 			= #{userId}
	,UPD_DT 			= now()
WHERE
	MEMBER_ID = #{userId}
AND
	AI_SEQ = #{aiSeq}

/* userSettingsMapper.deleteAccount */
UPDATE TB_ACCOUNT_INFO
SET
	 DEL_YN				= 'Y'
	,UPD_ID 			= #{userId}
	,UPD_DT 			= now()
WHERE
	MEMBER_ID = #{userId}
AND
	AI_SEQ = #{aiSeq}

