/* userSettingsMapper.selectCategoryList */ SELECT CATEGORY_CODE AS categoryCode ,CATEGORY_NAME AS categoryName FROM CATEGORY_CODE
AND CATEGORY_CODE = #{categoryCode}
ORDER BY CATEGORY_CODE

/* userSettingsMapper.selectCategorySeq */
SELECT
	IFNULL(MAX(CI_SEQ), 0) + 1
FROM
	TB_CATEGORY_INFO
WHERE
	MEMBER_ID = #{userId}
AND
	CATEGORY_CODE = #{categoryCode}

