mapper.insert:
/* userSettingsMapper.insertFixedExpense */
INSERT INTO TB_FIXED_EXPENSE_INFO (
	 MEMBER_ID
	,AI_SEQ
	,FEI_SEQ
	,CATEGORY_CODE
	,CI_SEQ
	,INOUT_TYPE
	,AMOUNT
	,TRAN_DAY
	,REMARK
	,DEL_YN
	,REG_ID
	,REG_DT
	,UPD_ID
	,UPD_DT
) VALUES (
	 #{userId}
	,#{aiSeq}
	,#{feiSeq}
	,#{categoryCode}
	,#{ciSeq}
	,#{inoutType}
	,REPLACE(#{amount}, ',', '')
	,#{tranDay}
	,#{remark}
	,'N'
	,#{userId}
	,now()
	,#{userId}
	,now()
)

mapper.update:
/* userSettingsMapper.updateFixedExpense */
UPDATE
	TB_FIXED_EXPENSE_INFO
SET
	 CATEGORY_CODE 	= #{categoryCode}
	,CI_SEQ 		= #{ciSeq}
	,INOUT_TYPE 	= #{inoutType}
	,AMOUNT 		= REPLACE(#{amount}, ',', '')
	,TRAN_DAY 		= #{tranDay}
	,REMARK 		= #{remark}
	,UPD_ID 		= #{userId}
	,UPD_DT 		= now()
WHERE
	MEMBER_ID = #{userId}
AND
	AI_SEQ = #{aiSeq}
AND
	FEI_SEQ = #{feiSeq}

/* userSettingsMapper.deleteFixedExpense */
UPDATE
	TB_FIXED_EXPENSE_INFO
SET
	 DEL_YN			= 'Y'
	,UPD_ID 		= #{userId}
	,UPD_DT 		= now()
WHERE
	MEMBER_ID = #{userId}
AND
	AI_SEQ = #{aiSeq}
AND
	FEI_SEQ = #{feiSeq}

